<script>
import { Radar, mixins } from "vue-chartjs";
import { mapGetters } from "vuex";
const { reactiveProp } = mixins;

export default {
  extends: Radar,
  mixins: [reactiveProp],
  props: ["chartData", "options"],
  computed: {
    isDark() {
      return this.$store.state.isDark;
    },
    ...mapGetters([
      "chartFontColor",
      "chartAngleLinesColor",
      "chartGridLinesColor",
    ]),
  },
  mounted() {
    this.updateColor();
    this.renderChart(this.chartData, this.options);
  },
  watch: {
    isDark(newValue, oldValue) {
      this.updateColor();
      this.renderChart(this.chartData, this.options);
    },
  },
  methods: {
    updateColor() {
      const { scale } = this.options;
      scale.ticks.fontColor = this.chartFontColor;
      scale.pointLabels.fontColor = this.chartFontColor;
      scale.angleLines.color = this.chartAngleLinesColor;
      scale.gridLines.color = this.chartGridLinesColor;
    },
  },
};
</script>
